import 'dart:io';import 'package:dio/dio.dart';import '../core/errors/app_error.dart';import 'models.dart';
class ApiRepository{ApiRepository(this.dio);final Dio dio;Future<T> _wrap<T>(Future<T> Function() f)async{try{return await f();}on DioException catch(e){throw AppError.fromDio(e);}}Future<UserProfile> createGuest(String n)=>_wrap(()async=>UserProfile.fromJson((await dio.post('/api/v1/users/guest',data:{'nickname':n})).data));Future<UserProfile> profile(String id)=>_wrap(()async=>UserProfile.fromJson((await dio.get('/api/v1/users/$id')).data));Future<Battle?> battle(String id)=>_wrap(()async{final r=await dio.get('/api/v1/battles/next',queryParameters:{'userId':id},options:Options(validateStatus:(s)=>s==200||s==204));return r.statusCode==204?null:Battle.fromJson(r.data);});Future<Map<String,Object?>> vote(String u,Battle b,String w)=>_wrap(()async=>(await dio.post('/api/v1/votes',data:{'userId':u,'leftMemeId':b.left.id,'rightMemeId':b.right.id,'winnerMemeId':w})).data);Future<List<MemeItem>> top(String p,{int limit=20})=>_wrap(()async=>(((await dio.get('/api/v1/memes/top',queryParameters:{'period':p,'limit':limit.clamp(1,100)})).data['items']) as List).cast<Map<String,Object?>>().map(MemeItem.fromJson).toList());Future<String> upload(String uid,File f)async=>_wrap(()async{final name=f.path.split('/').last;final fd=FormData.fromMap({'userId':uid,'file':await MultipartFile.fromFile(f.path,filename:name)});return ((await dio.post('/api/v1/media/images',data:fd)).data['id']).toString();});Future<void> createMeme(String uid,String title,String mediaId,String? source)=>_wrap(()async{await dio.post('/api/v1/memes',data:{'uploaderId':uid,'title':title,'mediaAssetId':mediaId,'sourceUrl':source?.isEmpty==true?null:source});});}
